Rule.Source:
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.object.Application;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  Log logger = LogFactory.getLog("Ascension-Global-Ministry-Rule");

  logger.debug("Start Ascension-Global-Ministry-Rule");

  String attributeValue = null;
  String domainVal = "";
  HashMap ministries = new HashMap();

  IdentityService idService = new IdentityService(context);
  Custom custom = context.getObjectByName(Custom.class, "Ascension-custom-generalConfiguration");

  if(custom != null && custom.get("MinistryDomainMapping") !=null){
    ministries = custom.get("MinistryDomainMapping");
    //comment decache //context.decache(custom);
  }


  if(null != identity){

    List<Link> appLinks = null;
    Application app = context.getObjectByName(Application.class,"DB-Peoplesoft-HCM-Primary");		
    Application midasApp = context.getObjectByName(Application.class,"Midas Seeker - Provider Onboarding");
    Application morriseyApp = context.getObjectByName(Application.class,"Morrisey");
    Application mdstaffAppAsc = context.getObjectByName(Application.class,"MDStaff - Ascension");
    Application mdstaffApp = context.getObjectByName(Application.class,"MDStaff - AMITA");

    if(null != app && !Util.isEmpty((appLinks = idService.getLinks( identity, app)))){	
      domainVal = appLinks.get(0).getAttribute("SETID_LOCATION");
      if(null != ministries && !ministries.isEmpty()){
        for (Map.Entry entry : ministries.entrySet()){             
          if(Util.isNotNullOrEmpty(domainVal) && null != entry.getValue() && entry.getValue().contains(domainVal)){
            attributeValue = entry.getKey();
          }
        }
      }			  
    } else if(null != midasApp && !Util.isEmpty((appLinks = idService.getLinks( identity, midasApp)))){ 
      attributeValue = "Saint Thomas Health Svcs-TN";
    } else if(null != morriseyApp && !Util.isEmpty((appLinks = idService.getLinks( identity, morriseyApp)))){
      attributeValue = "AMITA Health";								
    } else if(null != mdstaffAppAsc && !Util.isEmpty(appLinks = idService.getLinks( identity, mdstaffAppAsc))){ 
      domainVal = appLinks.get(0).getAttribute("Ministry_Domain");
      if(null != ministries && !ministries.isEmpty()){
        for (Map.Entry entry : ministries.entrySet()){             
          if(Util.isNotNullOrEmpty(domainVal) && null != entry.getValue() && entry.getValue().contains(domainVal)){
            attributeValue = entry.getKey();
          }
        }
      }				
    } else if(null != mdstaffApp && !Util.isEmpty(idService.getLinks( identity, mdstaffApp))){ 
      attributeValue = "AMITA Health";				
    } else if(Util.isNotNullOrEmpty(identity.getAttribute("ministry"))){        
      attributeValue = identity.getAttribute("ministry");
    } 

    if(null != app){
      //comment decache //context.decache(app);
    }
    if(null != midasApp){
      //comment decache //context.decache(midasApp);
    }
    if(null != morriseyApp){
      //comment decache //context.decache(morriseyApp);
    }	
    if(null != mdstaffAppAsc){
      //comment decache //context.decache(mdstaffAppAsc);
    }	
    if(null != mdstaffApp){
      //comment decache //context.decache(mdstaffApp);
    }
  }

  logger.debug("End Ascension-Global-Ministry-Rule");  
  return attributeValue;
